// domain/entities/order.ts
// ✅ Entidade pura — zero dependências externas

export interface OrderItem {
  productId: string;
  name: string;
  price: number;
  quantity: number;
}

export interface Order {
  id: string;
  items: OrderItem[];
  status: 'draft' | 'confirmed' | 'shipped' | 'delivered';
  createdAt: Date;
}

// Regras de negócio vivem AQUI, não no componente
export function calculateTotal(order: Order): number {
  return order.items.reduce((sum, item) => sum + item.price * item.quantity, 0);
}

export function canCancel(order: Order): boolean {
  return order.status === 'draft' || order.status === 'confirmed';
}

export function canShip(order: Order): boolean {
  return order.status === 'confirmed' && order.items.length > 0;
}

