// application/use-cases/useCreateOrder.ts
// O use case é um hook que orquestra entities + ports

import { useMutation, useQueryClient } from '@tanstack/react-query';
import type { Order, OrderItem } from '../../domain/entities/order';
import type { OrderRepository } from '../../domain/ports/orderRepository';

// Port: interface que define o que o use case precisa
// (equivalente à interface do repositório no Clean Architecture clássico)
export type { OrderRepository };

// Use case como hook — composable, testável, React-friendly
export function useCreateOrder(repo: OrderRepository) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (items: OrderItem[]) => {
      // Regras de negócio da entidade
      if (items.length === 0) throw new Error('Pedido vazio');
      if (items.some(i => i.quantity <= 0)) throw new Error('Quantidade inválida');

      // Delega ao repositório (adapter)
      return repo.create({ items });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['orders'] });
    },
  });
}

