// domain/ports/orderRepository.ts (PORT - só interface)
export interface OrderRepository {
  create(data: { items: OrderItem[] }): Promise<Order>;
  findById(id: string): Promise<Order>;
  list(): Promise<Order[]>;
}

// infrastructure/adapters/httpOrderRepository.ts (ADAPTER)
export function createHttpOrderRepository(baseUrl: string): OrderRepository {
  return {
    create: async (data) => {
      const res = await fetch(`${baseUrl}/orders`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });
      return res.json();
    },
    findById: async (id) => {
      const res = await fetch(`${baseUrl}/orders/${id}`);
      return res.json();
    },
    list: async () => {
      const res = await fetch(`${baseUrl}/orders`);
      return res.json();
    },
  };
}

// infrastructure/adapters/mockOrderRepository.ts (ADAPTER para testes)
export function createMockOrderRepository(): OrderRepository {
  const orders: Order[] = [];
  return {
    create: async (data) => {
      const order = { id: crypto.randomUUID(), ...data, status: 'draft' as const, createdAt: new Date() };
      orders.push(order);
      return order;
    },
    findById: async (id) => orders.find(o => o.id === id)!,
    list: async () => [...orders],
  };
}

