import { createContext, useContext, useMemo } from 'react';
import type { OrderRepository } from '../../domain/ports/orderRepository';
import { createHttpOrderRepository } from '../adapters/httpOrderRepository';

interface Dependencies {
  orderRepo: OrderRepository;
  // authRepo: AuthRepository;
  // analyticsService: AnalyticsService;
}

const DepsContext = createContext<Dependencies | null>(null);

export function DependencyProvider({ children }: { children: React.ReactNode }) {
  const deps = useMemo<Dependencies>(() => ({
    orderRepo: createHttpOrderRepository(import.meta.env.VITE_API_URL),
  }), []);

  return <DepsContext.Provider value={deps}>{children}</DepsContext.Provider>;
}

// Hook tipado para acessar dependências
export function useDeps(): Dependencies {
  const ctx = useContext(DepsContext);
  if (!ctx) throw new Error('useDeps must be used within DependencyProvider');
  return ctx;
}

// Uso no componente:
function OrderPage() {
  const { orderRepo } = useDeps();
  const createOrder = useCreateOrder(orderRepo);
  // ...
}

// Em testes:
function renderWithMockDeps(ui: ReactElement) {
  return render(
    <DependencyProvider deps={{ orderRepo: createMockOrderRepository() }}>
      {ui}
    </DependencyProvider>
  );
}

