function useCheckout() {
  const { orderRepo } = useDeps();
  // Regra de negócio justifica a camada extra
  return useMutation({
    mutationFn: async (cart: CartItem[]) => {
      const total = calculateTotal(cart);
      if (total < MIN_ORDER_VALUE) throw new Error('Pedido mínimo R$50');
      if (!hasStock(cart)) throw new Error('Sem estoque');
      return orderRepo.create({ items: cart, total });
    },
  });
}

